INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (23, 7, "プリン大好きゴースト娘", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 32, "プリンを食べること", 0, "B", "悪魔偽王国軍（ディアボロス）", "雨宮天", 130, 14, "ミヤコ", 100701, "魔族", 1);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (10, 15, "ボクは誰よりも美しい", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 40, "鏡で自分を見ること", 0, "AB", "ヴァイスフリューゲル　ランドソル支部", "大空直美", 150, 14, "ユキ", 100801, "エルフ", 10);
